{
  "domain_analysis": {
    "business_context": "Parcel delivery logistics platform managing shipment lifecycle from creation through transit to delivery, with weight-based pricing tiers.",
    "bounded_context": "Shipment Management — covers shipment creation, state transitions, weight validation, and pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A domain entity representing a parcel moving from a pickup address to a delivery address, with a defined weight and lifecycle state." },
      { "term": "Pickup Address", "definition": "The origin location where a parcel is collected. Required at shipment creation." },
      { "term": "Delivery Address", "definition": "The destination location where a parcel must be delivered. Required at shipment creation." },
      { "term": "Shipment State", "definition": "The lifecycle phase of a shipment. Valid states: Pending, In Transit, Delivered. Transitions are strictly forward-only." },
      { "term": "Weight Bracket", "definition": "A pricing classification derived from shipment weight: Standard (0–10 kg), Heavy (10–50 kg), Freight (>50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for shipments weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for shipments weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for shipments weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — it cannot be routed, priced, or fulfilled. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment missing a pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions are strictly forward-only: Pending → In Transit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "Backward transitions (e.g., In Transit → Pending) would corrupt operational state, mislead warehouse and driver systems, and break downstream audit trails. This is a state integrity constraint.",
      "testable_assertion": "A shipment in state In Transit cannot transition to Pending. A shipment in state Delivered cannot transition to any other state."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state. No further state changes are allowed on a delivered shipment.",
      "invariant": true,
      "invariant_justification": "Delivery finalizes the contractual obligation. Allowing mutation after delivery corrupts billing, proof-of-delivery records, and SLA reporting. This is a data consistency constraint.",
      "testable_assertion": "Any attempt to change the state of a Delivered shipment must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "Zero or negative weight is physically impossible for a real parcel. The 1000 kg ceiling represents a physical/operational hard limit (vehicle capacity, safety regulations). Violating this corrupts pricing and operational planning.",
      "testable_assertion": "Any shipment with weight ≤ 0 or weight > 1000 must be rejected at creation."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket classification: Standard = weight in (0, 10], Heavy = weight in (10, 50], Freight = weight in (50, 1000].",
      "invariant": false,
      "invariant_justification": "The bracket thresholds and names are business policy — management could adjust brackets (e.g., change Heavy to 10–60 kg) without corrupting system state.",
      "testable_assertion": "A 10 kg shipment is classified as Standard. A 10.01 kg shipment is classified as Heavy. A 50.01 kg shipment is classified as Freight."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A request to create a shipment with a valid pickup address, delivery address, and weight of 5 kg",
      "when": "The shipment is created",
      "then": "The shipment is persisted in Pending state with weight bracket Standard"
    },
    {
      "id": "AC-2",
      "given": "A request to create a shipment missing a pickup address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating pickup address is required"
    },
    {
      "id": "AC-3",
      "given": "A request to create a shipment missing a delivery address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating delivery address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in Pending state",
      "when": "The shipment transitions to In Transit",
      "then": "The state is updated to In Transit and the transition is recorded"
    },
    {
      "id": "AC-5",
      "given": "A shipment in In Transit state",
      "when": "An attempt is made to transition it back to Pending",
      "then": "The system rejects the transition and the shipment remains In Transit"
    },
    {
      "id": "AC-6",
      "given": "A shipment in In Transit state",
      "when": "The shipment transitions to Delivered",
      "then": "The state is updated to Delivered and the transition is recorded"
    },
    {
      "id": "AC-7",
      "given": "A shipment in Delivered state",
      "when": "Any state change is attempted",
      "then": "The system rejects the transition and the shipment remains Delivered"
    },
    {
      "id": "AC-8",
      "given": "A request to create a shipment with weight 0 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A request to create a shipment with weight 1001 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight exceeds the 1000 kg maximum"
    },
    {
      "id": "AC-10",
      "given": "A shipment with weight exactly 10 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Standard"
    },
    {
      "id": "AC-11",
      "given": "A shipment with weight 10.01 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Heavy"
    },
    {
      "id": "AC-12",
      "given": "A shipment with weight exactly 50 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Heavy"
    },
    {
      "id": "AC-13",
      "given": "A shipment with weight 50.01 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Freight"
    }
  ],

  "edge_cases": [
    { "scenario": "Shipment created with weight of exactly 10 kg (Standard/Heavy boundary)", "expected_behavior": "Classified as Standard per the bracket definition 0–10 kg inclusive." },
    { "scenario": "Shipment created with weight of exactly 50 kg (Heavy/Freight boundary)", "expected_behavior": "Classified as Heavy per the bracket definition 10–50 kg inclusive." },
    { "scenario": "Shipment created with weight of exactly 1000 kg (upper limit)", "expected_behavior": "Accepted and classified as Freight." },
    { "scenario": "Shipment created with negative weight (e.g., -1 kg)", "expected_behavior": "Rejected — weight must be strictly positive." },
    { "scenario": "Attempt to transition a Pending shipment directly to Delivered (skipping In Transit)", "expected_behavior": "Spec is silent on this. Needs clarification — see escalations." },
    { "scenario": "Attempt to create a shipment with a weight that has many decimal places (e.g., 10.000001 kg)", "expected_behavior": "System should apply consistent rounding or precision rules to classify correctly. Precision policy not specified — see escalations." },
    { "scenario": "Shipment with weight exactly at a floating-point boundary (e.g., 50.0 kg)", "expected_behavior": "Classified as Heavy (50 kg falls within the 10–50 bracket)." },
    { "scenario": "Pickup and delivery addresses are identical", "expected_behavior": "Spec does not prohibit this. May be a valid business scenario (e.g., return-to-sender) or a data entry error — see escalations." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly determines pricing tier. Misclassification at boundaries (10 kg, 50 kg) causes revenue leakage or customer overcharges. Correct state management prevents duplicate billing or missed delivery charges.",
    "operational": "Forward-only state machine prevents operational confusion — dispatchers and drivers rely on shipment state to plan routes and capacity. The 1000 kg cap protects fleet from unsafe loads.",
    "user": "Clear shipment lifecycle gives customers reliable tracking visibility. Rejected invalid shipments at creation time prevent downstream confusion and support tickets.",
    "risk": "Boundary precision errors in weight classification could cause systematic pricing errors at scale. Lack of clarity on Pending→Delivered skip transition could lead to inconsistent implementations across teams.",
    "stakeholders_affected": [
      { "group": "Customers (Shippers)", "impact": "Pricing accuracy and shipment tracking reliability directly affect trust and retention." },
      { "group": "Drivers / Couriers", "impact": "Shipment state integrity ensures accurate dispatch and delivery workflows." },
      { "group": "Finance / Billing", "impact": "Weight bracket accuracy determines invoice correctness. Terminal Delivered state ensures billing finality." },
      { "group": "Operations / Dispatch", "impact": "Forward-only state machine prevents re-dispatching already-in-transit or delivered parcels." },
      { "group": "Compliance / Safety", "impact": "1000 kg weight cap may relate to vehicle load regulations; must be enforced without exception." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is clear on core lifecycle and weight constraints but leaves several boundary questions unresolved: (1) whether Pending→Delivered is a valid skip transition, (2) weight precision/rounding policy, (3) whether same pickup/delivery address is allowed. These are not contradictions but genuine gaps that could lead to divergent implementations.",
    "high_confidence_areas": [
      "Forward-only state transitions (Pending → In Transit → Delivered)",
      "Delivered is terminal — no further changes",
      "Weight must be positive and ≤ 1000 kg",
      "Both addresses required at creation",
      "Three weight brackets with stated thresholds"
    ],
    "low_confidence_areas": [
      "Whether Pending → Delivered (skip In Transit) is allowed or prohibited",
      "Weight precision — decimal handling at bracket boundaries",
      "Whether pickup and delivery address can be the same",
      "Whether weight can be modified after shipment creation",
      "Whether bracket boundaries are inclusive on the lower or upper end (spec says '0-10' and '10-50' — overlap at 10 and 50)"
    ],
    "assumptions": [
      "Bracket boundaries are upper-inclusive: Standard = (0, 10], Heavy = (10, 50], Freight = (50, 1000]",
      "Weight is assigned at creation and is immutable thereafter",
      "A newly created shipment starts in Pending state",
      "Addresses are validated for basic structural correctness but geocoding is out of scope for this bounded context"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not clarify whether a shipment can skip from Pending directly to Delivered (bypassing In Transit). The stated transitions are 'In Transit cannot go back to Pending' and 'Delivered is final,' but no explicit rule governs Pending → Delivered.",
      "affected_stakeholders": ["Operations / Dispatch", "Drivers / Couriers", "Finance / Billing"],
      "options": [
        "A) Allow Pending → Delivered (supports edge cases like instant local delivery or cancellation-as-delivered)",
        "B) Require strict sequential transitions: Pending → In Transit → Delivered only"
      ],
      "recommendation": "Option B — require strict sequential transitions. In logistics, every shipment that reaches Delivered should have a recorded transit phase for audit trail, proof of chain-of-custody, and SLA measurement. Skipping transit creates gaps in operational visibility."
    },
    {
      "type": "ambiguity",
      "description": "Weight bracket boundaries overlap in the spec description: '0-10 kg is standard, 10-50 kg is heavy.' A shipment weighing exactly 10 kg matches both descriptions. Same overlap at 50 kg.",
      "affected_stakeholders": ["Finance / Billing", "Customers (Shippers)"],
      "options": [
        "A) Lower-inclusive brackets: Standard = [0, 10), Heavy = [10, 50), Freight = [50, 1000]",
        "B) Upper-inclusive brackets: Standard = (0, 10], Heavy = (10, 50], Freight = (50, 1000]"
      ],
      "recommendation": "Option B — upper-inclusive brackets favor the customer at boundaries (lower tier pricing), which is standard industry practice and reduces billing disputes."
    },
    {
      "type": "missing_context",
      "description": "No specification on weight precision or rounding policy. In practice, warehouse scales may report weights to varying decimal precision (e.g., 10.004 kg). Without a defined rounding rule, bracket classification could be inconsistent.",
      "affected_stakeholders": ["Finance / Billing", "Operations / Dispatch"],
      "options": [
        "A) Accept arbitrary decimal precision, classify on raw value",
        "B) Round to 2 decimal places (nearest gram-hundredths) before classification"
      ],
      "recommendation": "Option B — round to 2 decimal places. This aligns with industry standard weighing precision and ensures deterministic bracket classification."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not address whether a Cancelled state exists. Real-world logistics requires the ability to cancel shipments (e.g., customer cancellation before pickup). Without this, the system has no way to handle cancellations without violating the forward-only state rule.",
      "affected_stakeholders": ["Customers (Shippers)", "Operations / Dispatch", "Finance / Billing"],
      "options": [
        "A) Add a Cancelled state reachable from Pending only",
        "B) Add a Cancelled state reachable from Pending and In Transit",
        "C) Defer — handle cancellation outside the shipment lifecycle"
      ],
      "recommendation": "Option A at minimum — cancellation from Pending is nearly always needed. Option B depends on business appetite for mid-transit cancellation. Escalating for product decision."
    }
  ],

  "rejection_reasons": []
}

